// Mock data for library management system
export interface Book {
  id: string
  title: string
  author: string
  isbn: string
  category: string
  totalCopies: number
  availableCopies: number
  publishedYear: number
  description: string
  coverImage: string
}

export interface Member {
  id: string
  name: string
  email: string
  phone: string
  joinDate: string
  membershipStatus: "active" | "inactive"
  booksborrowed: number
  totalFines: number
}

export interface BorrowRecord {
  id: string
  bookId: string
  bookTitle: string
  memberId: string
  memberName: string
  borrowDate: string
  dueDate: string
  returnDate: string | null
  status: "borrowed" | "returned" | "overdue" | "missing"
  fine: number
}

